      void sendDiscordLog({ event: "Script Auth — Key Blacklisted", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License blacklisted", timestamp: new Date().toISOString() });
      return errorResponse("License is blacklisted", 403);
    }
    if (license.status === "EXPIRED" || (license.expiresAt && new Date() > license.expiresAt)) {
      if (license.status !== "EXPIRED") {
        await db.license.update({ where: { id: license.id }, data: { status: "EXPIRED" } });
      }
      await logAccess(false, "LICENSE_EXPIRED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Expired", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License expired", timestamp: new Date().toISOString() });
      return errorResponse("License has expired", 403);
    }

    // HWID lock — auto-bind on first use
    let hwidRecord = await db.hwid.findFirst({ where: { licenseId: license.id, fingerprintHash } });
    if (license.hwidLock) {
      if (!hwidRecord && license.hwids.length > 0) {
        await logAccess(false, "HWID_MISMATCH", license.id);
        void sendDiscordLog({ event: "Script Auth — HWID Mismatch", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "HWID mismatch", timestamp: new Date().toISOString() });
        return errorResponse("HWID mismatch — reset HWID from dashboard");
      }
      if (!hwidRecord) {
        hwidRecord = await db.hwid.create({
          data: { licenseId: license.id, fingerprintHash, source: "auth", lastIp: ip, lastDeviceInfo: userAgent },
