    }

    return new NextResponse(scriptPayload, {
      headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "private, no-store" },
    });
  } catch (error) {
    console.error("Auth script endpoint error:", error);
    return errorResponse("Internal server error", 500);
  }
}

import { redis } from "./redis";

export interface RateLimitResult {
  success: boolean;
  limit: number;
  remaining: number;
  reset: number;
}

const localWindows = new Map<string, { count: number; resetAt: number }>();

async function redisRateLimit(key: string, limit: number, windowMs: number): Promise<RateLimitResult> {
  const now = Date.now();
  const resetAt = now + windowMs;
  const multi = redis.multi();
  multi.incr(key);
  multi.expire(key, Math.ceil(windowMs / 1000));
  const results = await multi.exec();
  if (!results) {
    return localRateLimit(key, limit, windowMs);
  }

  const [count] = results;

  const current = Number((count as any)?.[1] ?? 1);
  const ttl = await redis.ttl(key);
  const reset = now + Math.max(ttl, 1) * 1000;

  return {
    success: current <= limit,
    limit,
    remaining: Math.max(limit - current, 0),
    reset,
  };
}

function localRateLimit(key: string, limit: number, windowMs: number): RateLimitResult {
  const now = Date.now();
  const entry = localWindows.get(key);

  if (!entry || now > entry.resetAt) {
    localWindows.set(key, { count: 1, resetAt: resetAtFrom(now, windowMs) });
    return result(true, limit, limit - 1, entry?.resetAt ?? localWindows.get(key)!.resetAt);
  }

  if (entry.count >= limit) {
    return result(false, limit, 0, entry.resetAt);
  }

  entry.count += 1;
  return result(true, limit, limit - entry.count, entry.resetAt);
}

function resetAtFrom(now: number, windowMs: number) {
  return now + windowMs;
}

function result(success: boolean, limit: number, remaining: number, reset: number): RateLimitResult {
  return { success, limit, remaining, reset };
}

export async function rateLimit(key: string, limit = 60, windowMs = 60000): Promise<RateLimitResult> {
  if (redis.status === "ready") {
    return redisRateLimit(key, limit, windowMs);
  }

  return localRateLimit(key, limit, windowMs);
}

export function getRateLimitHeaders(result: RateLimitResult) {
  return {
    "X-RateLimit-Limit": result.limit.toString(),
    "X-RateLimit-Remaining": result.remaining.toString(),
    "X-RateLimit-Reset": Math.ceil(result.reset / 1000).toString(),
  };
}

