export function middleware(request: NextRequest) {
  const isApiRoute = request.nextUrl.pathname.startsWith("/api/");
  const isPublicApi = request.nextUrl.pathname.startsWith("/api/v1/");

  // Handle OPTIONS preflight for public API routes only
  if (request.method === "OPTIONS" && isPublicApi) {
    const response = NextResponse.next();
    response.headers.set("Access-Control-Allow-Origin", "*");
    response.headers.set("Access-Control-Allow-Methods", "GET, POST, OPTIONS");
    response.headers.set("Access-Control-Allow-Headers", "Content-Type, User-Agent");
    response.headers.set("Access-Control-Max-Age", "86400");
    return response;
  }

  const response = NextResponse.next();

  // Add CORS headers only for public executor-facing API routes
  if (isPublicApi) {
    response.headers.set("Access-Control-Allow-Origin", "*");
    response.headers.set("Access-Control-Allow-Methods", "GET, POST, OPTIONS");
    response.headers.set("Access-Control-Allow-Headers", "Content-Type, User-Agent");
  }

  for (const [key, value] of Object.entries(securityHeaders)) {
    response.headers.set(key, value);
  }

  // Dashboard auth guard
  if (
    request.nextUrl.pathname.startsWith("/dashboard") &&
    !request.cookies.get("token")?.value
  ) {
    return redirectToLogin(request);
  }

  // Skip CSRF for public API routes (Roblox executors, external clients)
  if (isPublicApi) {
    return response;
  }

  if (!verifyCsrf(request)) {
    return NextResponse.json(
      { error: "CSRF validation failed" },
      { status: 403, headers: securityHeaders },
    );
  }

  return response;
}

